+        {
+            let mut chain = WitnessChain::create(&path).unwrap();
+            chain.record_store("a", "ns").unwrap();
+            chain.record_store("b", "ns").unwrap();
+        }
+
+        let chain = WitnessChain::open(&path).unwrap();
+        assert_eq!(chain.len(), 2);
